                isDark ? 'text-white' : 'text-slate-900'
              }`}>{exp.role}</h4>
              <p className={`text-[10px] font-bold uppercase tracking-widest transition-colors ${
                isDark ? 'text-blue-400' : 'text-blue-600'
              }`}>{exp.company}</p>
            </div>
