  const [newComment, setNewComment] = useState('');

  const isM3 = theme === 'material3';
  const isDark = mode === 'dark';

  const handleCommentSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newComment.trim()) {
      onAddComment(newComment);
