                  isDark ? 'text-blue-500/50' : 'text-blue-600/50'
                }`} />
                {h}
              </li>
            ))}
          </ul>

          {exp.details && (
            <div className="pt-2">
              <button 
                onClick={() => setIsOpen(!isOpen)}
